func resizeHandleClass(axis ResizeAxis) string {
	if axis == ResizeAxisY {
		return "app-resize-handle app-resize-handle--horizontal"
	}
	return "app-resize-handle app-resize-handle--vertical"
}

func resizeHandlerClass(props PanelResizeHandlerProps) string {
	class := "min-h-0 min-w-0 [&>.app-resize-handle]:h-full [&>.app-resize-handle]:w-full"
	if !props.Visible {
		class += " hidden"
	}
	return class
}

func resizeHandleOrientation(axis ResizeAxis) string {
	if axis == ResizeAxisY {
		return "horizontal"
	}
	return "vertical"
}

func resizeHandleLabel(props ResizeHandleProps) string {
	if props.Label != "" {
		return props.Label
	}
	if props.Axis == ResizeAxisY {
		return "Resize panel height"
	}
	return "Resize panel width"
}

func resizeHandlerStyle(props PanelResizeHandlerProps) ahtempl.SafeCSS {
	style := ""
	if props.GridColumn != "" {
		style += "grid-column: " + props.GridColumn + ";"
	}
	if props.GridRow != "" {
		style += " grid-row: " + props.GridRow + ";"
	}
	return ahtempl.SafeCSS(style)
}

